module gray_counter(CLK, RST, Gray);
input CLK, RST;
output [1:0] Gray;
reg [1:0] Gray;
reg [1:0] invalid_binary;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        invalid_binary <= 0;
        Gray <= 0;
    end else begin
        invalid_binary <= invalid_binary + 1;
        Gray <= (invalid_binary >> 1) ^ invalid_binary;
    end
end

endmodule
